"""
requests ‚Äî friendly HTTP client built on top of urllib.request.

This is a pure-Python module bundled with the pyaot compiler. It wraps the
standard `urllib.request.Request + urlopen` pattern with helper functions
that follow the public API of the well-known `requests` library.

The code uses ONLY standard stdlib APIs and is intended to work identically
on any Python interpreter (CPython 3.x, pyaot, etc.) without modification.

Usage:
    resp = requests.get("https://api.example.com/items", params={"q": "x"})
    resp.status_code    # int
    resp.text           # str
    resp.json()         # Any

Supported kwargs on get / post / put / delete:
    params      dict[str, str] | None   URL query-string parameters
    headers     dict[str, str] | None   extra HTTP headers
    auth        tuple[str, str] | None  HTTP Basic auth (user, pass)
    timeout     float                   seconds, default 30.0

post / put additionally accept:
    data        bytes | str | dict[str, str] | None   request body
    json        dict[str, str] | None                 JSON body (sets Content-Type)

TODO (compiler follow-ups ‚Äî tracked in .claude/rules/pkg-dev.md):
- `verify=False` ‚Äî requires exposing `ssl.SSLContext` as a runtime type and
  passing `context=` to urlopen. Not currently supported.
- `allow_redirects=False` ‚Äî requires `build_opener()` + custom
  `HTTPRedirectHandler` from stdlib. Not currently supported.
"""

from urllib.request import urlopen, Request
from urllib.parse import urlencode
from urllib.error import HTTPError
from http.client import HTTPResponse
from base64 import b64encode
from json import dumps as _json_dumps
from typing import Any, Optional


def _basic_auth_header(user: str, password: str) -> str:
    token = b64encode((user + ":" + password).encode()).decode()
    return "Basic " + token


def _build_headers(
    headers: Optional[dict[str, str]],
    auth: Optional[tuple[str, str]],
    auto_content_type: Optional[str],
) -> dict[str, str]:
    """Collapse user headers + auth + auto-derived content-type into one dict.

    User headers are applied first. `auth` then overrides any existing
    Authorization header. `auto_content_type` is applied only if the user
    didn't set one.
    """
    merged: dict[str, str] = {}
    if headers is not None:
        for k, v in headers.items():
            merged[k] = v
    if auth is not None:
        merged["Authorization"] = _basic_auth_header(auth[0], auth[1])
    if auto_content_type is not None and "Content-Type" not in merged:
        merged["Content-Type"] = auto_content_type
    return merged


def _append_query(url: str, params: Optional[dict[str, str]]) -> str:
    if params is None:
        return url
    sep = "&" if "?" in url else "?"
    return url + sep + urlencode(params)


def _prepare_body(data, json_data: Optional[dict[str, str]]) -> tuple[bytes, Optional[str]]:
    """Return `(body_bytes, auto_content_type)` derived from data / json."""
    if json_data is not None:
        return _json_dumps(json_data).encode(), "application/json"
    if data is None:
        return b"", None
    if isinstance(data, bytes):
        return data, None
    if isinstance(data, str):
        return data.encode(), None
    if isinstance(data, dict):
        return urlencode(data).encode(), "application/x-www-form-urlencoded"
    raise TypeError("requests: data must be bytes, str, dict, or None")


def _send(
    method: str,
    url: str,
    body: bytes,
    hdrs: dict[str, str],
    timeout: float,
) -> Any:
    # Pass empty body as None so urllib uses a proper GET/DELETE with no
    # body. Avoid ternary expressions ‚Äî they currently interact badly with
    # the cross-module value-passing path for Optional[Heap] slots.
    body_arg: Optional[bytes] = None
    if len(body) > 0:
        body_arg = body
    # Use kwarg form ‚Äî CPython's Request positional layout interleaves
    # `origin_req_host` and `unverifiable` before `method`, which would
    # make `Request(url, body_arg, hdrs, method)` bind method wrongly.
    req = Request(url, data=body_arg, headers=hdrs, method=method)
    # CPython's urlopen() raises `HTTPError` on 4xx/5xx by default; the real
    # pip `requests` library and pyaot's runtime both return the response
    # object instead. Catch and surface the HTTPError as a response so this
    # facade has uniform behaviour on every interpreter. HTTPError is a
    # subclass of HTTPResponse in CPython so it satisfies the return type;
    # pyaot's HTTPError is a stub exception that is never actually raised by
    # the runtime (this catch is therefore a no-op on pyaot).
    try:
        return urlopen(req, None, timeout)
    except HTTPError as e:
        return e


def get(
    url: str,
    params: Optional[dict[str, str]] = None,
    headers: Optional[dict[str, str]] = None,
    auth: Optional[tuple[str, str]] = None,
    timeout: float = 30.0,
) -> HTTPResponse:
    final_url = _append_query(url, params)
    hdrs = _build_headers(headers, auth, None)
    return _send("GET", final_url, b"", hdrs, timeout)


def post(
    url: str,
    data=None,
    json: Optional[dict[str, str]] = None,
    params: Optional[dict[str, str]] = None,
    headers: Optional[dict[str, str]] = None,
    auth: Optional[tuple[str, str]] = None,
    timeout: float = 30.0,
) -> HTTPResponse:
    final_url = _append_query(url, params)
    body, auto_ct = _prepare_body(data, json)
    hdrs = _build_headers(headers, auth, auto_ct)
    return _send("POST", final_url, body, hdrs, timeout)


def put(
    url: str,
    data=None,
    json: Optional[dict[str, str]] = None,
    params: Optional[dict[str, str]] = None,
    headers: Optional[dict[str, str]] = None,
    auth: Optional[tuple[str, str]] = None,
    timeout: float = 30.0,
) -> HTTPResponse:
    final_url = _append_query(url, params)
    body, auto_ct = _prepare_body(data, json)
    hdrs = _build_headers(headers, auth, auto_ct)
    return _send("PUT", final_url, body, hdrs, timeout)


def delete(
    url: str,
    params: Optional[dict[str, str]] = None,
    headers: Optional[dict[str, str]] = None,
    auth: Optional[tuple[str, str]] = None,
    timeout: float = 30.0,
) -> HTTPResponse:
    final_url = _append_query(url, params)
    hdrs = _build_headers(headers, auth, None)
    return _send("DELETE", final_url, b"", hdrs, timeout)
